#nullable enable // autogenerated

using System.Collections.Generic;
using System.Xml;
using MVZ2.IO;
using MVZ2Logic.Options;

namespace MVZ2.Metas
{
    public class OptionItemMeta
    {
        public OptionItemType Type { get; private set; }
        public string ID { get; private set; }
        public object? DefaultValue { get; private set; }

        public OptionItemMeta(OptionItemType type, string iD)
        {
            Type = type;
            ID = iD;
        }
        public static OptionItemMeta? FromXmlNode(XmlNode node, string defaultNsp)
        {
            var id = node.GetAttribute("id");
            if (string.IsNullOrEmpty(id))
            {
                Log.LogError($"The {nameof(id)} of a {nameof(OptionItemMeta)} is invalid.");
                return null;
            }
            OptionItemType type = OptionItemType.Boolean;
            if (typeDict.TryGetValue(node.Name, out var t))
            {
                type = t;
            }

            object? defaultValue = null;
            switch (type)
            {
                case OptionItemType.Boolean:
                    defaultValue = node.GetAttributeBool("defaultValue") ?? false;
                    break;
                case OptionItemType.Int:
                    defaultValue = node.GetAttributeInt("defaultValue") ?? 0;
                    break;
                case OptionItemType.Float:
                    defaultValue = node.GetAttributeFloat("defaultValue") ?? 0;
                    break;
                case OptionItemType.String:
                    defaultValue = node.GetAttribute("defaultValue") ?? string.Empty;
                    break;
                case OptionItemType.ID:
                    defaultValue = node.GetAttributeNamespaceID("defaultValue", defaultNsp);
                    break;
            }
            return new OptionItemMeta(type, id)
            {
                DefaultValue = defaultValue
            };
        }
        private static readonly Dictionary<string, OptionItemType> typeDict = new Dictionary<string, OptionItemType>()
        {
            { "bool", OptionItemType.Boolean },
            { "int", OptionItemType.Int },
            { "float", OptionItemType.Float },
            { "string", OptionItemType.String },
            { "id", OptionItemType.ID },
        };
    }
}
